module RefModule(
    input clk,
    input rst,
    input load,
    input [3:0] data_in,
    output [3:0] count_out
);reg [3:0] obf_count;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        obf_count <= 4'b0000;
    end else if (load) begin
        obf_count <= data_in;
    end else begin
        obf_count <= obf_count + 1;
    end
end

assign count_out = obf_count;

endmodule
